#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        if(N==0){
            printf("[]\n");
            continue;
        }
        int *val = (int*)malloc(N*sizeof(int));
        int *rnd = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++){
            scanf("%d %d", &val[i], &rnd[i]);
        }
        printf("[");
        for(int i=0;i<N;i++){
            printf("[%d,%d]", val[i], rnd[i]);
            if(i!=N-1) printf(",");
        }
        printf("]\n");
        free(val); free(rnd);
    }
    return 0;
}

