    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        if(N==0){
            cout<<"[]\n";
            continue;
        }
        vector<int> val(N), rnd(N);
        for(int i=0;i<N;i++) cin>>val[i]>>rnd[i];
        cout<<"[";
        for(int i=0;i<N;i++){
            cout<<"["<<val[i]<<","<<rnd[i]<<"]";
            if(i!=N-1) cout<<",";
        }
        cout<<"]\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for(int tc=0; tc<T; tc++){
            int N = Integer.parseInt(br.readLine().trim());
            if(N==0){
                out.append("[]\n");
                continue;
            }
            int[] val = new int[N];
            int[] rnd = new int[N];
            for(int i=0;i<N;i++){
                StringTokenizer st = new StringTokenizer(br.readLine());
                val[i] = Integer.parseInt(st.nextToken());
                rnd[i] = Integer.parseInt(st.nextToken());
            }
            out.append('[');
            for(int i=0;i<N;i++){
                out.append('[').append(val[i]).append(',').append(rnd[i]).append(']');
                if(i!=N-1) out.append(',');
            }
            out.append(']').append('\n');
        }
        System.out.print(out.toString());
    }
}

