const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (input.length === 0) process.exit(0);
const T = parseInt(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = parseInt(input[idx++]);
  if (N === 0) {
    outputs.push('[]');
    continue;
  }
  const vals = new Array(N);
  const rnd = new Array(N);
  for (let i = 0; i < N; i++) {
    vals[i] = parseInt(input[idx++]);
    rnd[i] = parseInt(input[idx++]);
  }
  const parts = [];
  for (let i = 0; i < N; i++) {
    parts.push(`[${vals[i]},${rnd[i]}]`);
  }
  outputs.push('[' + parts.join(',') + ']');
}
